import type {ArticleSection} from '../types/philosophy';

const section=(id:string,title:string,paragraphs:string[],relatedBranchIds?:string[],relatedPhilosopherIds?:string[],relatedWorkTitles?:string[]):ArticleSection=>({id,title,paragraphs,relatedBranchIds,relatedPhilosopherIds,relatedWorkTitles});

export const romanHellenisticPhilosopherArticles:Record<string,ArticleSection[]>={
  zeno:[
    section('overview','From ethical independence to a new philosophical system',[
      'Zeno of Citium founded Stoicism by bringing several demanding inheritances into a new relation. From Socratic philosophy came the claim that virtue and the condition of the soul matter more than reputation or fortune. From Cynicism came a radical challenge to convention, luxury, and dependency. From wider Greek philosophy came problems about knowledge, language, causation, nature, and the structure of the cosmos. Zeno did not merely attach practical advice to these materials. He established a school in which logic, physics, and ethics could explain how rational and social beings should live within an ordered but uncontrollable world.',
      'Almost all of Zeno’s writings are lost, so the founder is difficult to separate from the later system developed by Cleanthes, Chrysippus, and generations of Stoics. Ancient biographies preserve titles, anecdotes, doctrines, and disputes, but often use stories to express character rather than provide documentary history. Zeno must therefore be read as both a historical thinker and the remembered origin of a tradition. What can be seen clearly is the shape of his intervention: ethical freedom required more than rejecting wealth or status. It required an account of reason, nature, community, and the judgments through which circumstances gain power over a life.'
    ],['stoicism','cynicism','ethics'],['socrates','diogenes','cleanthes','chrysippus'],[]),
    section('hellenistic-athens','Hellenistic Athens after Alexander',[
      'Zeno arrived in an Athens that remained intellectually prestigious while its political independence had been transformed by Macedonian power and the conflicts following Alexander’s death. Plato’s Academy and Aristotle’s Lyceum had made philosophy institutionally durable, but new schools increasingly addressed lives lived amid large kingdoms, war, migration, and uncertain civic power. Epicurus founded the Garden around the same period; skeptical argument developed in the Academy; Cynics publicly exposed the artificiality of status and convention. These schools disagreed about nature and value while sharing the demand that philosophy become a practiced way of life.',
      'Stoicism’s answer to this setting was neither private withdrawal nor confidence that political success could secure happiness. Zeno located the good in virtue, which fortune cannot supply or remove, while understanding human beings as parts of a rational and social cosmos. This made resilience inseparable from obligation. A person should not depend on office or applause for moral worth, yet should still act appropriately toward family, city, and humanity. The Hellenistic setting matters because Stoic freedom is designed for agents whose responsibilities remain real even when control over institutions and outcomes is limited.'
    ],['stoicism','epicureanism','skepticism','ancient-greek'],['zeno','epicurus'],[]),
    section('citium-arrival','Citium, arrival, and the stories of a philosophical conversion',[
      'Zeno was born in Citium on Cyprus, probably around 334 BCE. Citium was a culturally mixed trading city with Greek and Phoenician connections, and ancient descriptions of Zeno sometimes emphasize his foreign origin. Later reports tell that he came to Athens after a shipwreck, encountered Xenophon’s Memorabilia in a bookseller’s shop, and asked where people like Socrates could be found. The bookseller supposedly pointed to the Cynic Crates. The story may be shaped as a philosophical conversion narrative, but it captures how later Stoics understood the school’s beginning: commercial loss becomes an encounter with a good that fortune cannot wreck.',
      'Ancient sources also associate Zeno with several teachers, including Crates, Stilpo, and philosophers connected with the Academy. The varied education helps explain why Stoicism cannot be reduced to polished Cynicism. Zeno learned from traditions concerned with argument, definition, and knowledge as well as from Cynic practice. His foreign status in Athens also complicates the school’s civic identity. He became a respected teacher without simply becoming an Athenian political figure. The school that emerged could speak to citizenship and law while grounding human community more broadly than membership in one city.'
    ],['stoicism','cynicism','ancient-greek'],['zeno','socrates','antisthenes'],['Memorabilia']),
    section('crates-cynicism','Crates, Cynicism, and the limits of shame',[
      'The Cynic Crates represented a philosophy enacted publicly through simplicity, frank speech, and refusal of conventional shame. Cynics treated wealth, rank, elaborate education, and social approval as sources of dependency rather than components of happiness. Zeno inherited their insistence that virtue is sufficient and that a philosopher must be prepared to expose customs that masquerade as nature. Ancient anecdotes describe Crates testing Zeno’s lingering concern for respectability, suggesting that philosophical freedom required loosening the fear of public embarrassment.',
      'Zeno did not preserve every Cynic stance. Stoicism developed technical logic, systematic physics, and a positive theory of appropriate action within social roles. It could value health, resources, and civic participation as preferred without making them morally good. This transformation answered a weakness in radical Cynic independence: how should a person who rejects conventional measures still explain responsible selection, family relation, law, or cooperative institutions? Zeno kept the Cynic challenge at the center of Stoicism while building a framework capable of distinguishing principled participation from servitude to convention.'
    ],['cynicism','stoicism','ethics'],['diogenes','antisthenes','zeno'],[]),
    section('painted-porch','The Painted Porch and the act of founding a school',[
      'Zeno taught in the Stoa Poikile, the Painted Porch in the Athenian Agora. The school came to be called Stoic after this public place rather than after its founder. That naming matters. Unlike a philosophy identified only with one charismatic life, Stoicism became a teachable and disputable institution whose positions could be inherited, criticized, and revised. Students gathered around arguments associated with the porch, and successors could lead the school without claiming to reproduce Zeno’s personality.',
      'The location also joined philosophy to civic memory. The porch displayed paintings connected with Athenian history and war, and it stood within the commercial and political life of the city. Zeno’s teaching was therefore public without being reducible to political office. Founding a school created continuity: Cleanthes could preserve and develop the project, Chrysippus could answer technical objections, and later Stoics could adapt it to Roman settings. Zeno’s achievement lies partly in making ethical independence institutionally shareable, a conversation strong enough to outlive the loss of nearly all his own books.'
    ],['stoicism','ancient-greek'],['zeno','cleanthes','chrysippus'],[]),
    section('three-parts','Logic, physics, and ethics as one undertaking',[
      'Early Stoics divided philosophy into logic, physics, and ethics, although surviving reports differ about how Zeno himself arranged their relation. Logic included reasoning, language, rhetoric, and the criteria by which impressions could be accepted as knowledge. Physics studied bodies, causes, soul, divine reason, and the ordered cosmos. Ethics studied the good life, virtue, action, and social relation. These were not independent departments. An agent cannot live according to nature without understanding nature, and cannot judge impressions responsibly without training in reasoning.',
      'The integrated structure distinguishes Stoicism from a collection of maxims. When a person fears exile, logic asks what judgment has been accepted; physics places the event within causal nature; ethics asks what response expresses virtue and appropriate social conduct. Zeno laid the foundation for this architecture, while Chrysippus later supplied much of its technical defense. Modern readers often retain practical exercises while setting aside providence or formal logic. That can produce a valuable reconstruction, but it differs from the ancient ambition to explain why disciplined judgment fits the character of reality as a whole.'
    ],['stoicism','logic','metaphysics','ethics'],['zeno','chrysippus'],[]),
    section('nature-good-life','Virtue, reason, nature, and the good life',[
      'Zeno is associated with the formula of living consistently or living in agreement, later developed as living in agreement with nature. The ideal does not mean following appetite or treating whatever occurs as morally right. Human beings possess rational and social capacities, and excellent life requires coherent use of them within the larger natural order. Virtue is the only genuine good because it alone makes every circumstance into material for good action. Wealth, health, office, and reputation may be reasonably selected, but none can make an unjust or foolish life good.',
      'This argument gives Stoic freedom its distinctive shape. If external success is good in the same sense as virtue, agents must sometimes sacrifice justice to secure it and remain vulnerable to anyone who can threaten its loss. If virtue alone determines moral worth, action can remain committed without being desperate for control. The claim is severe because pain and deprivation are real burdens, and critics have long argued that happiness cannot be insulated from them so completely. Zeno’s school nevertheless changes ethical debate by asking whether fortune should possess authority over the basic judgment that a life is good.'
    ],['stoicism','virtue-ethics','ethics'],['zeno','aristotle','epicurus'],[]),
    section('republic','The radical Republic',[
      'Zeno wrote a Republic, now lost, that ancient reports remembered as radical and strongly marked by Cynic influence. It apparently imagined a community in which conventional institutions and divisions would be transformed or abolished, and later readers associated it with shared life, unconventional sexual and family arrangements, and the rejection of money, courts, or temples. Because the work survives through polemical summaries, its exact proposals and relation to Zeno’s mature thought are uncertain. It should not be treated as a complete constitutional blueprint recoverable from fragments.',
      'The Republic matters because it reveals the political pressure inside early Stoicism. If virtue rather than citizenship, wealth, or legal status defines worth, many ordinary institutions appear irrational. The work tests what community among wise people would look like when convention no longer governs attachment and authority. Later Stoicism often speaks more readily through existing roles and duties, but cosmopolitan ideas preserve part of this challenge. Zeno’s radical text prevents the school from becoming only advice for coping within institutions; its founding imagination also asks how institutions would change if rational fellowship replaced inherited hierarchy.'
    ],['stoicism','political-philosophy','cynicism'],['zeno','diogenes'],['Republic']),
    section('successors','Cleanthes, Chrysippus, and the school beyond its founder',[
      'Cleanthes succeeded Zeno and preserved the school through intellectual persistence and teaching. His surviving Hymn to Zeus expresses the Stoic vision of a cosmos governed by rational law, while reports associate him with developments in physics and theology. Chrysippus then produced an enormous body of argument across logic, causation, psychology, and ethics. Ancient testimony treats his work as decisive to Stoicism’s survival because he answered objections and made the system technically formidable.',
      'The successors make attribution difficult. A doctrine routinely called Stoic may be Zeno’s proposal, Chrysippus’ refinement, or a later reconstruction. Yet that difficulty also demonstrates the importance of founding a school. Zeno created a project capable of correction rather than a set of sayings tied permanently to his authority. Cleanthes and Chrysippus did not merely popularize him; they transformed and defended the inheritance. Roman Stoics later emphasized moral exercise and social roles, but their practices still depend on the early architecture of virtue, reason, nature, and assent initiated at the Painted Porch.'
    ],['stoicism','logic','ethics'],['zeno','cleanthes','chrysippus','epictetus'],['Hymn to Zeus']),
    section('fragments','Reading a founder whose books are lost',[
      'Zeno reportedly wrote works on the good life, passions, law, education, nature, signs, poetry, and Homer as well as the Republic. None survives intact. Knowledge comes through later biographies, summaries, quotations, doxographies, critics, and accounts of Stoicism that may reflect later developments. Diogenes Laertius is indispensable but wrote centuries afterward and combines valuable evidence with anecdotes shaped by literary convention. Cicero and other writers preserve philosophical disputes while translating them into their own contexts and purposes.',
      'Responsible reading therefore distinguishes levels of confidence. A title or attributed claim may establish that Zeno addressed a problem without revealing his full argument. A vivid anecdote may disclose how the tradition represented his character without documenting an event. A later systematic doctrine may grow from Zeno while bearing Chrysippus’ conceptual form. This fragmentary condition is not a reason to make the founder generic. It is a reason to explain reconstruction openly and to see the school itself as part of the evidence: Zeno’s most durable work was the argumentative community that preserved, revised, and sometimes obscured him.'
      ,'Comparison among hostile and sympathetic witnesses can sometimes recover the problem a doctrine was designed to solve even when its wording remains uncertain. If critics repeatedly attack Stoic claims about virtue or knowledge, their objections help reveal the position’s pressure points. Reconstruction is therefore argumentative rather than archaeological assembly alone: readers ask which claims must have been connected for a reported dispute to make sense.'
    ],['stoicism','ancient-greek'],['zeno','cleanthes','chrysippus'],['Republic']),
    section('legacy-reading','Legacy inside Stoicism and how to read Zeno',[
      'Zeno’s legacy appears wherever later Stoics connect moral freedom to rational nature and social obligation. Cleanthes develops cosmic piety; Chrysippus builds the logical and causal system; Panaetius and Posidonius adapt the school; Seneca, Epictetus, and Marcus Aurelius translate its principles into Roman ethical practice. The famous later distinction between what depends on us and what does not is not simply Zeno’s slogan, but it develops within the structure he helped establish: virtue belongs to rational agency, while external outcomes do not determine the good.',
      'Begin with a reliable collection of early Stoic fragments and reports rather than expecting a surviving book by Zeno. Read accounts of his life critically, comparing the shipwreck, Crates, and the Painted Porch stories with the doctrines they are meant to illuminate. Then read Cleanthes’ Hymn to Zeus and selected evidence for Chrysippus before moving to Roman Stoics. Keep the founder’s tensions visible: Cynic radicalism and systematic philosophy, individual independence and social nature, public teaching and cosmopolitan belonging. Zeno matters not because every later Stoic claim can be traced word for word to him, but because he made those tensions into a durable school.'
    ],['stoicism','cynicism','ethics'],['zeno','cleanthes','chrysippus','seneca','epictetus','marcus-aurelius'],['Republic','Hymn to Zeus'])
  ],
  seneca:[
    section('overview','Philosophy written from inside compromise',[
      'Seneca writes Stoic philosophy from a position that seems designed to test it. He was extraordinarily wealthy, politically powerful, vulnerable to imperial violence, implicated in an autocratic court, and repeatedly concerned with the distance between moral teaching and actual conduct. His essays and letters do not speak from a life purified of contradiction. They ask how a person who is ambitious, frightened, angry, distracted, privileged, and mortal might make progress without pretending already to possess wisdom.',
      'This tension explains both Seneca’s force and the accusations against him. If philosophy requires a flawless teacher, his wealth and proximity to Nero disqualify him. If philosophy is a practice for diagnosing dependency and correcting judgment under compromised conditions, those failures become part of the evidence. Seneca does not resolve every charge, and historical judgment cannot be replaced by admiration for his prose. His writing is valuable because it makes self-examination occur near money, power, danger, friendship, illness, and death, where abstract allegiance to virtue becomes difficult to sustain.'
    ],['stoicism','ethics','political-philosophy'],['seneca','epictetus','marcus-aurelius'],['Moral Letters']),
    section('imperial-context','A Roman life under imperial power',[
      'Born at Corduba in Roman Spain around the beginning of the first century CE, Seneca was educated at Rome and entered a political culture in which advancement depended on elite networks and imperial favor. He suffered serious illness, developed as an orator and statesman, and encountered Stoic and other philosophical teachers. Under Claudius he was exiled to Corsica, then recalled and made tutor to the young Nero. He later became one of the emperor’s advisers during the early years of the reign.',
      'Imperial politics made ethical independence urgent and dangerous. A senator or adviser could possess great status while remaining dependent on the ruler’s mood. Seneca’s writings about anger, clemency, benefits, exile, and death belong to this environment of unequal power. They analyze how fear and hope turn people into flatterers and how rulers become enslaved to rage. Seneca eventually withdrew from public life as his relationship with Nero deteriorated. In 65 CE, accused of involvement in the Pisonian conspiracy, he was ordered to die and complied through a carefully staged suicide remembered by later writers.'
    ],['stoicism','political-philosophy','ancient-greek'],['seneca'],[]),
    section('near-nero','Nero and the problem of philosophy near power',[
      'Seneca’s role near Nero raises a question with no comfortable answer: can philosophy improve power from within without becoming its ornament or accomplice? The treatise On Clemency addresses the young emperor and argues that restraint, mercy, and rational self-command distinguish legitimate rule from tyranny. The work attempts to shape imperial conduct through Stoic-inflected moral psychology, yet its praise and political rhetoric also show the compromises required to advise an autocrat. Later violence under Nero makes the project appear tragically inadequate.',
      'Seneca benefited materially and politically during the regime, and accounts differ about the extent of his responsibility for decisions and excesses. Treating him simply as Nero’s innocent moral tutor excuses too much; treating every text as hypocrisy prevents inquiry into why ethically serious people remain near destructive power. Seneca’s case asks when withdrawal becomes necessary, whether counsel can restrain wrongdoing, and how dependence on influence distorts judgment. His philosophy of benefits and freedom is sharpened by the fact that he never occupied a position outside these entanglements.',
      'Withdrawal itself is morally ambiguous. Leaving a dangerous court may preserve integrity and remove cooperation from wrongdoing, but it may also surrender influence, abandon vulnerable people, or arrive only after the adviser’s position becomes insecure. Seneca’s attempts to retire and return wealth to Nero show how difficult it was to end a relationship structured by imperial permission. The episode turns a Stoic question about externals into a political one: a person may claim indifference to office and property while discovering that power decides whether either can actually be relinquished.'
    ],['stoicism','political-philosophy','ethics'],['seneca'],['On Clemency']),
    section('letters','The Moral Letters and the drama of progress',[
      'The Moral Letters to Lucilius present philosophy through an extended correspondence addressed to a friend. Seneca discusses time, travel, noise, illness, crowds, reading, friendship, slavery, death, wealth, and the daily work of examining oneself. The letters are literary compositions rather than a transparent private archive, and Lucilius’ replies do not survive. Their form nevertheless matters. Seneca writes as a fellow learner who advises, confesses, tests formulations, and returns to problems that knowledge has not yet solved in practice.',
      'The recurring distinction is between possessing philosophical language and being changed by it. Reading many books can become distraction; quoting teachers can become borrowed authority; planning to live later can waste the only time available. Seneca urges concentrated reading, daily review, and conversion of precepts into settled judgment. The letters gradually engage more technical issues while keeping them connected to formation. They show Stoic progress as uneven: a person may understand that death is not evil and still fear it, or condemn status anxiety while continuing to enjoy recognition.'
    ],['stoicism','ethics'],['seneca','epicurus'],['Moral Letters']),
    section('anger','Anger as a judgment that recruits power',[
      'On Anger analyzes a passion especially dangerous in households, courts, and imperial government. Seneca rejects the claim that anger is a useful ally of courage or punishment. Once granted authority, it does not reliably stop at a rational limit. Anger interprets an injury as intolerable and retaliation as appropriate, then narrows attention until cruelty appears justified. Because it involves judgment and assent rather than an unavoidable natural force, it can be prevented, delayed, and corrected through education and practice.',
      'Seneca distinguishes initial involuntary reactions from the developed passion. A startle, flush, or shock is not yet the full endorsement that revenge is good. Practical measures include pausing, recognizing one’s own fallibility, changing environments, anticipating provocation, and refusing to punish while emotionally captured. The analysis is political as well as personal. Anger becomes catastrophic when powerful people can act on it without resistance. Seneca’s proximity to imperial violence gives the argument urgency, even as it raises the question of whether private counsel and self-command are enough to constrain institutions organized around arbitrary power.'
    ],['stoicism','ethics','political-philosophy'],['seneca','chrysippus'],['On Anger']),
    section('time-death','Time, death, and the life postponed',[
      'On the Shortness of Life argues that life is not simply too brief; much of it is surrendered to distraction, ambition, service to other people’s agendas, and anxious preparation for a future that never becomes present. The busy person can be socially admired while lacking possession of time. Seneca’s target is not activity itself but unexamined occupation that makes a person absent from their own life. Philosophy gathers time by clarifying what deserves attention and by refusing the fantasy that living can safely be deferred.',
      'Death supplies the sharpest test of this reorientation. Seneca repeatedly rehearses mortality, not to cultivate gloom but to reduce the power of threats and delays. Every day includes a form of dying because elapsed time is no longer available; no amount of status changes that condition. A person prepared to die is harder to coerce, yet Seneca’s discussions also reflect a Roman elite tradition that could idealize suicide. Modern readers should resist turning death-readiness into a simple solution to suffering. Its philosophical role is to expose whether fear has made integrity conditional on indefinite survival.'
    ],['stoicism','ethics'],['seneca','epictetus','marcus-aurelius'],['On the Shortness of Life','Moral Letters']),
    section('benefits-friendship','Benefits, friendship, and social dependence',[
      'On Benefits examines giving, receiving, gratitude, obligation, and the social relationships created by exchange. A benefit is not merely the object transferred; it includes the intention and relation through which something is given. This distinction allows Seneca to ask how generosity differs from patronage used to purchase submission, how gratitude can avoid servility, and why a failed return does not erase the goodness of a generous act. In a hierarchical Roman society, these questions concern both moral character and the organization of power.',
      'Friendship similarly tests Stoic self-sufficiency. The wise person does not need a friend in the sense of being unable to live well without one, but still actively wants friendship and gives themselves within it. Seneca’s letters construct philosophy as a shared practice rather than solitary possession. This creates productive tension: if virtue is sufficient, why do relationships matter so deeply? Seneca’s answer is that self-sufficiency removes desperate dependence, not affection or responsibility. A friend is not an instrument against loneliness but another person with whom excellent activity and mutual correction become possible.'
    ],['stoicism','ethics','political-philosophy'],['seneca','epicurus'],['On Benefits','Moral Letters']),
    section('wealth-fortune','Wealth, fortune, and the accusation of hypocrisy',[
      'Seneca argues that wealth is a preferred indifferent rather than a moral good. A wise person can possess resources without being possessed by them, use them generously, and remain prepared for their loss. Critics ancient and modern respond that this distinction is convenient for an extremely wealthy man. Seneca’s fortune and conduct near power make the charge philosophically serious. A theory of detachment can conceal material privilege when the speaker keeps every benefit while praising readiness to surrender it.',
      'Seneca often presents himself as making progress rather than claiming sagehood. That admission does not settle whether his choices were defensible, but it changes the question. Hypocrisy can mean knowingly using ideals as camouflage, or it can name the common failure to live up to convictions one sincerely accepts. His writing repeatedly turns accusation inward, asking whether luxury has created dependency and whether public values have colonized desire. Reading him well requires both suspicion and engagement: compare doctrine with life, while asking whether compromised practitioners can still articulate standards that judge them.',
      'The distinction between using wealth and serving it also demands external evidence. Readiness for loss cannot be measured only by a writer’s self-description; it appears in acquisition, generosity, political conduct, and the burdens imposed on others. Seneca’s case therefore pushes Stoic moral psychology toward social criticism. A person’s inner relation to property matters, but property also organizes real relations of dependence that private detachment may leave unchanged.'
    ],['stoicism','ethics','political-philosophy'],['seneca','epictetus'],['On the Happy Life','Moral Letters']),
    section('tragedies','Tragedy and the imagination of passion',[
      'Seneca’s tragedies portray rage, revenge, desire, tyranny, and inherited violence at an intensity unlike the measured voice of many essays. Their relation to his philosophical project and performance context remains debated, but they offer a dramatic laboratory for passions that escape rational government. Figures such as Medea, Thyestes, and Phaedra do not merely illustrate doctrinal errors. Their language shows how imagination, grievance, and power construct worlds in which terrible action appears necessary.',
      'The tragedies complicate the image of Stoicism as emotional flattening. Seneca is acutely interested in the seductions and momentum of passion. Dramatic form can make readers experience how a judgment recruits memory and fantasy before it becomes catastrophe. The plays also expose political terror, including rulers whose unrestrained desires spread suffering beyond themselves. Read beside On Anger and On Clemency, they suggest that moral psychology cannot be separated from institutions that amplify one person’s passions into public disaster.'
    ],['stoicism','aesthetics','political-philosophy'],['seneca'],['Medea','Thyestes','Phaedra']),
    section('stoic-inheritance','Earlier Stoicism and Roman moral culture',[
      'Seneca inherits the Stoic system developed by Zeno, Cleanthes, and Chrysippus: virtue is the only good, externals are indifferent with respect to moral worth, nature is rationally ordered, and passions involve judgments. He sometimes complains about excessive technical subtlety, yet he does not abandon logic or physics. His Natural Questions connects investigation of the world with liberation from fear and moral enlargement. Understanding nature helps a person see ordinary ambition from a wider scale and recognize participation in a common cosmos.',
      'His expression of Stoicism is also deeply Roman. He writes within traditions of exemplarity, public service, household authority, patronage, and moral exhortation. He quotes Epicurus frequently, arguing that useful truth can be taken from a rival camp. This openness does not erase disagreement with Epicurean pleasure or withdrawal; it supports Seneca’s view that philosophy should heal rather than police ownership of insights. His Latin prose makes Greek arguments available in a form suited to Roman readers and later European moralists.'
    ],['stoicism','epicureanism','philosophy-of-science'],['zeno','cleanthes','chrysippus','epicurus'],['Natural Questions','Moral Letters']),
    section('reception-reading','Reception and how to read Seneca',[
      'Seneca’s writings were read extensively by Christian authors, medieval moralists, Renaissance humanists, essayists, dramatists, and political thinkers. Readers found affinities in conscience, examination, providence, contempt for luxury, and preparation for death while transforming Stoic theology and ethics. His tragedies influenced European drama, and his compressed moral style became a model for reflection on public life. Modern Stoicism often returns to his treatments of time, anger, grief, and adversity, sometimes detaching them from the political contradictions that give them weight.',
      'Begin with selected Moral Letters, including letters on time, friendship, crowds, slavery, illness, and death. Read On the Shortness of Life and On Anger as sustained arguments rather than collections of quotations, then add On Benefits or On Clemency to confront social exchange and imperial power. A tragedy such as Thyestes reveals another register of his moral psychology. Throughout, keep biography and argument in conversation without letting either end the inquiry. Seneca is most instructive when the question remains difficult: what can philosophy demand from a person who understands virtue while continuing to benefit from the world that compromises it?'
    ],['stoicism','ethics','political-philosophy'],['seneca','epictetus','marcus-aurelius'],['Moral Letters','On Anger','On the Shortness of Life','On Benefits','On Clemency','Thyestes'])
  ],
  'marcus-aurelius':[
    section('overview','An emperor practicing rather than displaying philosophy',[
      'Marcus Aurelius is remembered as a philosopher-emperor, but the surviving text that sustains that reputation was not written as a public philosophical treatise. The Meditations are private notes of correction, recollection, and rehearsal composed by a ruler trying to keep Stoic principles available amid administration, illness, war, loss, irritation, and enormous power. Their repeated commands are addressed first to Marcus himself. He returns to the same lessons because understanding them once has not made their practice automatic.',
      'This private setting changes how the work should be read. A severe sentence about accepting events may be an emperor restraining resentment, fear, vanity, or self-pity rather than a universal command imposed on someone without power. Marcus repeatedly reminds himself that other people act from their judgments, that authority does not make anger rational, and that a human being is made for cooperative action. The Meditations matter not because the ruler achieved perfect wisdom, but because they reveal moral self-government as unfinished work inside a position capable of governing millions.'
    ],['stoicism','ethics','political-philosophy'],['marcus-aurelius','epictetus'],['Meditations']),
    section('imperial-crisis','Rule amid war, plague, and administrative burden',[
      'Marcus was born in 121 CE and became emperor in 161, initially ruling alongside Lucius Verus. His reign faced wars on several frontiers, internal political strain, natural disasters, and the epidemic commonly called the Antonine plague. He spent substantial periods away from Rome with military campaigns and administration. The Meditations contain headings associated with campaign locations, though they offer little direct political narrative. Their compressed reminders arise from a life in which decisions, reports, ceremonies, petitions, and conflict continually competed for attention.',
      'Stoic practice under these conditions cannot be understood simply as stress management. Marcus’ judgments had public consequences, and the discipline of action concerned justice as well as composure. His reign also belonged to an imperial system built through conquest, hierarchy, and slavery. The philosophical claim that all rational beings share a common nature sits uneasily beside Roman domination. A responsible account holds both facts together: Marcus sought rational and cooperative rule within the institutions he inherited, yet Stoic humility did not dissolve the coercive structure or make imperial decisions morally innocent.',
      'The Meditations rarely tells readers which administrative decisions Marcus made after a morning exercise or how Stoic principles affected a particular campaign. That silence prevents the notebook from serving as proof of good government. Historical evaluation must use legal, narrative, epigraphic, and material evidence while recognizing their own limits. Philosophy can clarify the standards Marcus set for himself, but the consequences of rule must also be judged from the lives governed, taxed, recruited, punished, and protected by imperial institutions.'
    ],['stoicism','political-philosophy','ethics'],['marcus-aurelius','seneca'],['Meditations']),
    section('formation','Education, adoption, and philosophical formation',[
      'Marcus was raised within the Roman elite and adopted into the succession planned by the emperor Antoninus Pius. His education included rhetoric, law, literature, and philosophy. In the first book of the Meditations, he names qualities learned from relatives, teachers, friends, and models: gentleness, endurance, seriousness, generosity, freedom from display, and willingness to be corrected. The catalogue presents character as socially formed rather than self-created. Even an emperor’s moral resources are received through relationships and remembered examples.',
      'Stoicism became his principal philosophical framework, but the Meditations also show a reader drawing from a broad moral culture. Marcus admired the disciplined philosopher’s plain manner and rejected the temptation to perform intellectual distinction. His gratitude toward teachers is itself an exercise against imperial self-sufficiency. By remembering how much he owes others, he counters the fantasy that rank makes him the source of every good. This opening also prepares the work’s cosmopolitan ethics: a rational person belongs within networks of dependence and contribution, not above them.'
    ],['stoicism','ethics'],['marcus-aurelius','epictetus'],['Meditations']),
    section('private-notes','The Meditations as private exercises',[
      'The work now called the Meditations survives in Greek and was not given that title by Marcus. Its books contain varying forms: short injunctions, extended reflections, remembered quotations, arguments, images, and lists. Repetition is structural, not evidence of editorial failure. Marcus rehearses mortality, impermanence, social duty, and the testing of impressions because daily pressures repeatedly obscure them. The text resembles a philosophical workbook in which a practitioner reformulates doctrines until they become available at the moment of action.',
      'Because the notes were not designed as a systematic introduction, isolated passages can mislead. Marcus presupposes Stoic distinctions concerning impressions, assent, virtue, nature, appropriate action, and preferred indifferents. He sometimes considers alternative physical pictures, asking whether events arise through providence or atoms, while insisting that ethical conduct remains required. Readers should resist treating every line as a polished final doctrine. The work documents an active attempt to persuade oneself, and its tensions may reveal the changing needs of that exercise rather than theoretical inconsistency alone.'
    ],['stoicism','ethics'],['marcus-aurelius','epictetus','epicurus'],['Meditations']),
    section('epictetus','Epictetus and the inherited disciplines',[
      'Epictetus is the most visible philosophical influence on the Meditations. Marcus thanks a teacher for introducing him to notes associated with Epictetus, and he repeatedly uses distinctions familiar from the Discourses: events and other people’s actions are not under one’s command, while judgment and the use of impressions belong to moral agency. External things do not enter and damage the ruling faculty by themselves; the interpretation granted to them determines their moral force.',
      'Marcus adapts this teaching to imperial life. He must distinguish responsible action from the demand that subjects, colleagues, enemies, weather, bodies, or history cooperate with his plans. The distinction can restrain tyranny because frustration does not justify rage, and public failure does not excuse injustice. Yet an emperor has much greater external power than Epictetus’ ordinary student, so the ethical burden is correspondingly different. Marcus’ task is not merely to endure what he cannot change, but to use real authority without allowing it to corrupt judgment or erase the standing of others.'
    ],['stoicism','ethics','political-philosophy'],['epictetus','marcus-aurelius'],['Discourses','Meditations']),
    section('three-disciplines','Perception, action, and desire',[
      'A useful way to organize Marcus’ practice is through disciplines of perception or assent, action, and desire. The discipline of perception strips an impression of the dramatic interpretation attached to it. Luxurious food can be described as dead animal matter; fame as sounds produced by changing people; an insult as another person’s judgment. This redescription is not meant to prove that nothing matters. It prevents appearance, appetite, and social prestige from dictating value before reason has examined them.',
      'The discipline of action directs attention toward justice and the common good. A deed should express the social nature of a rational being rather than vanity or resentment. The discipline of desire accepts the unfolding of nature without demanding that events satisfy private preference. Together, the disciplines prevent tranquility from becoming withdrawal. Perception clarifies the material, desire releases impossible control, and action still asks what service and responsibility require. Marcus fails and begins again, which is why the same triad appears through many formulations rather than once as a completed method.'
    ],['stoicism','ethics','epistemology'],['marcus-aurelius','epictetus'],['Meditations']),
    section('impermanence-death','Impermanence, death, and the scale of reputation',[
      'Marcus repeatedly places individual concerns against the scale of time and cosmic change. Emperors, conquerors, critics, admirers, and remembered names disappear; bodies transform; generations replace one another. The exercise reduces the apparent magnitude of praise, insult, possession, and fear. Reputation cannot secure a good life because future admirers will themselves be temporary and governed by unstable judgments. Death belongs to nature’s process rather than standing as an exception that makes life meaningless.',
      'These reflections can sound bleak when detached from their purpose. Marcus does not argue that action is pointless because everything passes. Impermanence clarifies why present character and service cannot be postponed for immortal recognition. A finite action can be just without lasting forever. The recurring thought of death also disciplines imperial vanity: rule does not exempt Marcus from the condition shared with every person. At its best, the cosmic perspective returns him to ordinary duty with less fear and self-importance, rather than inviting contempt for particular lives.'
    ],['stoicism','ethics','metaphysics'],['marcus-aurelius','seneca'],['Meditations']),
    section('social-nature','Cosmopolitanism, duty, and rational nature',[
      'Marcus treats human beings as parts of a common rational and social whole. The image of citizens in one cosmic city extends obligation beyond local preference. Because people are made for cooperation, hostility and exploitation damage the agent’s own nature as well as the victim. Marcus compares social obstruction to the impossibility of separating a limb from the body without loss. Other people’s errors should therefore prompt instruction, patience, or protective action rather than hatred.',
      'This ideal is tested by difficult encounters. Marcus begins one famous reflection by anticipating meddling, ingratitude, arrogance, deceit, jealousy, and hostility, then reminds himself that wrongdoers act from confused judgments and remain kin in reason. The exercise does not require allowing every harmful action to continue. It seeks a response guided by justice rather than retaliation. The gap between cosmopolitan language and Roman imperial hierarchy remains substantial. Still, the doctrine gives the emperor a standard that criticizes domination by anger, contempt, and personal glory.'
    ],['stoicism','political-philosophy','ethics'],['marcus-aurelius','epictetus'],['Meditations']),
    section('power-humility','Imperial power and Stoic humility',[
      'The philosopher-emperor ideal can become flattering mythology. Marcus’ private reminders of humility do not by themselves establish that every policy was just, and ancient sources do not permit his reign to be read simply from the Meditations. Questions about warfare, persecution, legal hierarchy, slavery, and succession require historical evidence beyond the notebook. Stoic self-command can moderate a ruler, but it can also leave the institution of concentrated power insufficiently questioned.',
      'The tension is philosophically productive because Marcus recognizes several dangers of rule: theatricality, anger at opposition, dependence on praise, and the belief that office changes moral worth. He reminds himself not to be “Caesarified,” to remain teachable, and to perform the work of a human being. These exercises make power answerable to character but do not provide a full political theory or institutional safeguard. Modern admiration should therefore distinguish a ruler’s effort at moral discipline from the stronger claim that virtue alone can make imperial power legitimate.',
      'Stoicism locates moral good in the use of agency, but political office multiplies the number of people affected by that use. For an emperor, a mistaken impression can become an order, a delayed correction can become policy, and preference can become law. Marcus’ exercises in pausing and removing resentment therefore have institutional stakes even when written privately. At the same time, reliance on the ruler’s character reveals a weakness: subjects need accountable institutions, not only the hope that concentrated power will be exercised by someone practicing self-command.'
    ],['stoicism','political-philosophy','ethics'],['marcus-aurelius','seneca'],['Meditations']),
    section('misreadings','Why quotation culture misreads the Meditations',[
      'The Meditations is unusually easy to excerpt. Its short formulations travel well as advice about focus, adversity, and self-command. Quotation can introduce readers to the work, but it often removes the speaker, addressee, and system. A line written by an emperor to check his own anger may become an instruction for powerless people to accept mistreatment. A reminder that judgment shapes disturbance may become denial of material harm. A call to duty may become a productivity slogan detached from justice and cosmopolitan obligation.',
      'Popular readings also imagine Marcus as naturally serene. The notebook shows something more useful: repeated effort by a person who remains distractible, irritated, fearful, tired, and vulnerable to vanity. Its severity is often the sound of self-correction, not effortless superiority. Reading passages in sequence reveals how mortality, nature, social duty, and assent support one another. The work should not be protected from criticism, but neither should it be reduced to fragments whose only test is whether they feel motivational.'
    ],['stoicism','ethics'],['marcus-aurelius'],['Meditations']),
    section('legacy-reading','The philosopher-emperor and how to read Marcus',[
      'Marcus became an enduring image of the philosopher-ruler, a reputation shaped by both the Meditations and later narratives of his reign. Christian, humanist, modern philosophical, military, political, and self-help readers have adopted his exercises for different purposes. The appeal is understandable: the text brings cosmic perspective and moral discipline into direct contact with exhaustion and responsibility. Its status as private writing also creates an unusual intimacy, although readers should remember that the apparent private voice belongs to an emperor formed within a distant social world.',
      'Begin with Book I to see character acknowledged as a gift from others, then read several books continuously rather than assembling favorite lines. Pair the Meditations with selected Discourses of Epictetus to recover the arguments behind impressions, agency, and roles. Add historical study of Marcus’ reign so the notebook is not treated as a complete record of rule. Ask throughout who is speaking to whom. Notice also which problems keep returning, because repetition identifies the temptations that imperial status and ordinary human vulnerability did not allow Marcus to solve once and leave behind. The most responsible use of Marcus is not to command others to endure, but to test whether one’s own judgment, desire, and exercise of power serve justice within a shared human community.'
    ],['stoicism','ethics','political-philosophy'],['marcus-aurelius','epictetus','seneca'],['Meditations','Discourses'])
  ]
};

export const romanHellenisticBranchArticles:Record<string,ArticleSection[]>={
  skepticism:[
    section('overview','Inquiry that refuses premature settlement',[
      'Philosophical skepticism is not simply the belief that nothing can be known. It is a family of practices and arguments that test claims to knowledge, expose unresolved conflict, and ask what follows when inquiry cannot justify assent. Ancient skeptical traditions differ sharply. Academic skeptics developed within Plato’s Academy and challenged Stoic claims to certainty, sometimes defending the conclusion that knowledge is unavailable or proposing practical standards short of knowledge. Pyrrhonian skeptics avoid dogmatic conclusions in either direction and continue investigating while suspending judgment where opposing considerations remain balanced.',
      'This makes skepticism an activity before it is a doctrine. The skeptic asks how a claim is supported, whether its criterion can be justified without circularity, whether equally persuasive alternatives exist, and whether disagreement has genuinely been resolved. Suspension of judgment is not chosen through indifference to truth. It occurs when inquiry reveals that available reasons do not warrant a settled claim. Ancient skeptics report that tranquility can follow this suspension because the compulsion to settle what remains unsettled loses its hold.'
    ],['skepticism','epistemology','ancient-greek'],['pyrrho','sextus-empiricus'],[]),
    section('pyrrho','Pyrrho and the uncertain beginning of Pyrrhonism',[
      'Pyrrho of Elis, who lived in the fourth and early third centuries BCE, wrote nothing. Knowledge of him comes through later reports, especially traditions connected with his follower Timon and much later Pyrrhonists. Ancient stories portray unusual calm and indifference, but their historical reliability is difficult to assess. Pyrrho may have accompanied Alexander’s expedition eastward, yet claims about direct philosophical influence from Indian thinkers exceed what the evidence securely establishes.',
      'A report preserved through Aristocles attributes to Pyrrho or Timon a sequence of questions about what things are like, how people should be disposed toward them, and what follows. Interpreters dispute whether the answer makes a dogmatic claim that things are indeterminate or recommends withholding claims about their nature. This dispute matters because later Pyrrhonism defines itself against dogmatism. Pyrrho functions as an exemplary origin whose life suggests freedom from anxious judgment, while the argumentative practice familiar from Sextus Empiricus developed through later centuries.'
    ],['skepticism','ancient-greek'],['pyrrho','sextus-empiricus'],[]),
    section('academy','Skepticism inside Plato’s Academy',[
      'Academic Skepticism arose within the institution founded by Plato. Arcesilaus, who led the Academy in the third century BCE, used Socratic and dialectical methods against claims to knowledge, especially the Stoic theory of the cognitive impression. Stoics argued that some impressions possess a reliable character through which the wise person can recognize truth. Arcesilaus pressed the possibility that a false impression could be indistinguishable from a true one, making the proposed criterion unsafe.',
      'The skeptical turn was not necessarily a rejection of Plato. Dialogues repeatedly stage failed definitions, expose false confidence, and distinguish inquiry from possession of wisdom. Academic skeptics could present their practice as faithful to this interrogative inheritance. Yet rivals accused them of making action impossible: if one withholds assent, how can one choose anything? Reports associate Arcesilaus with practical standards such as what is reasonable, though interpretation remains contested. The Academy transformed skepticism into an organized challenge to the epistemic confidence of another school.',
      'Academic and Pyrrhonian skepticism should not be collapsed into one position. Sextus portrays Academics as making claims about the impossibility of knowledge, while presenting Pyrrhonists as suspending even that conclusion; historians debate whether this contrast treats the Academy fairly. The disagreement reveals a recurring skeptical danger: criticism of dogmatism can harden into a negative doctrine. Different skeptics answer by calibrating what, if anything, may be asserted after certainty has been challenged.'
    ],['skepticism','platonism','epistemology','stoicism'],['plato','socrates','zeno','chrysippus'],[]),
    section('carneades','Carneades, persuasion, and acting without certainty',[
      'Carneades became the most famous later Academic skeptic. He developed powerful arguments against Stoic epistemology, theology, fate, and ethics, often arguing opposing sides without announcing a final doctrine. During an embassy to Rome, he reportedly gave speeches for and against justice, alarming traditionalists who saw dialectical skill as a threat to moral conviction. The episode captures the skeptical capacity to reveal that arguments treated as obvious may depend on assumptions their defenders have not examined.',
      'Carneades is associated with the persuasive or probable appearance as a practical guide. An appearance can be convincing, mutually consistent with related appearances, and tested with care without becoming infallible knowledge. This framework answers the inactivity objection by distinguishing reasonable action from certainty. It also introduces a difficult question: can a skeptic endorse probabilities without dogmatically asserting the theory that makes them probable? Later Academics disagreed about how positively to formulate their position, showing that skepticism’s own practical standards remain subject to skeptical scrutiny.'
    ],['skepticism','epistemology','stoicism','political-philosophy'],['chrysippus'],[]),
    section('sextus','Sextus Empiricus and later Pyrrhonism',[
      'Sextus Empiricus, probably writing in the late second or early third century CE, provides the fullest surviving account of Pyrrhonian skepticism. His Outlines of Pyrrhonism and works Against the Learned collect arguments directed at logic, knowledge, physics, ethics, grammar, mathematics, and other disciplines. Sextus presents the skeptic as an inquirer who has not discovered the truth but does not claim that it cannot be discovered. This distinguishes the Pyrrhonist from both the dogmatist who claims discovery and the negative dogmatist who declares discovery impossible.',
      'Sextus’ writing is therapeutic and adversarial. Arguments are used to counterbalance the confidence produced by other arguments, like remedies adjusted to the strength of a disturbance. A skeptical expression such as “no more” or “I suspend judgment” reports a present condition rather than establishing a timeless fact. Even skeptical formulas can be discarded after doing their work. This reflexivity protects the practice from becoming another system of conclusions, although critics ask whether any coherent inquiry can avoid commitments about reason, language, and evidence.'
    ],['skepticism','epistemology','ancient-greek'],['sextus-empiricus','pyrrho'],['Outlines of Pyrrhonism','Against the Learned']),
    section('suspension','Equipollence and suspension of judgment',[
      'Equipollence occurs when opposed accounts appear equal in persuasive force. The skeptic investigates a claim, sets arguments and appearances against one another, and finds no non-question-begging basis for preferring one side. Suspension of judgment, epoché, follows. It is not a proof that the sides are objectively equal or that truth does not exist. Such claims would exceed the skeptical position. Suspension describes the inability or refusal to assent where the inquiry has not produced a justified resolution.',
      'Pyrrhonian modes organize routes toward this result. Arguments from disagreement ask why one disputed position deserves priority. Regress arguments ask for the support of each supporting reason. Relativity reveals how appearances vary with perceivers and conditions. Hypothesis challenges unsupported starting points, and circularity exposes claims supported by what they are meant to establish. These modes remain recognizable in contemporary epistemology. Their force does not depend on theatrical doubt about everything at once; they identify recurring structures through which justification can fail.'
    ],['skepticism','epistemology','logic'],['sextus-empiricus'],['Outlines of Pyrrhonism']),
    section('appearances-life','Appearances, belief, and living without dogma',[
      'The inactivity objection asks how skeptics can eat, travel, speak, practice medicine, or avoid danger without beliefs. Sextus answers that skeptics follow appearances without adding dogmatic claims about how things are by nature. Pyrrhonian life is guided by natural capacities, bodily feelings, customs and laws, and instruction in arts or skills. Hunger prompts eating; an apparent road can be followed; medical practice can respond to symptoms. The skeptic does not need certainty about ultimate reality before acting.',
      'Whether this amounts to living entirely without belief depends on how belief is defined. Sextus often targets assent to non-evident theoretical claims while permitting ordinary responsiveness. Critics argue that language and intentional action require more commitment than the skeptic admits. The debate reveals skepticism’s practical importance: it distinguishes the confidence needed for action from the stronger claim to possess truth about underlying nature. Fallible participation may remain possible even when philosophical explanation is suspended.'
    ],['skepticism','epistemology','ethics'],['sextus-empiricus'],['Outlines of Pyrrhonism']),
    section('tranquility','Tranquility and the skeptical therapy of disturbance',[
      'Pyrrhonists report that tranquility followed suspension of judgment as a shadow follows a body. The seeker originally investigates because conflicting appearances and theories create disturbance and hopes that discovering the truth will settle it. When inquiry instead leads to suspension, anxiety about deciding the undecidable unexpectedly loosens. This is not a guaranteed psychological mechanism or the sole reason to investigate. If tranquility were pursued dogmatically as a result that must occur, skepticism could create a new form of frustration.',
      'Sextus distinguishes disturbance caused by unavoidable feelings from the added torment of judgments. Pain still hurts, but the belief that pain is by nature an absolute evil can multiply suffering through fear, shame, and resistance. This resembles therapeutic aims in Stoicism and Epicureanism while differing in method. Stoics correct judgments through doctrines about virtue and nature; Epicureans remove fear through atomism and a theory of pleasure; Pyrrhonists counterbalance claims until assent relaxes. Skeptical tranquility arises from non-settlement rather than a settled account of the good.'
    ],['skepticism','stoicism','epicureanism','ethics'],['sextus-empiricus','epictetus','epicurus'],[]),
    section('dogmatism-rivals','Dogmatism, Stoicism, and Epicureanism',[
      'Ancient skeptics use dogmatism broadly for claims that non-evident matters have been discovered. Stoicism is a central opponent because it defends cognitive impressions, providential causal order, and knowledge possessed by the sage. Academic skeptics challenge whether any impression bears a mark unavailable to false appearances. Pyrrhonists deploy Stoic and anti-Stoic arguments against one another, refusing to conclude either that the system is true or that it has been finally refuted.',
      'Epicureanism offers another confident therapy. Sensation supplies criteria for knowledge, atoms and void explain nature, and arguments about gods and death remove fear. Skeptics can ask whether inference from appearances establishes imperceptible atoms and whether the criteria justify themselves. Yet skeptical practice also depends on inherited arguments from dogmatic schools; it often achieves balance by making rival theories confront one another. Skepticism is therefore not intellectual emptiness. It is a parasitic and productive art of revealing where systems exceed the reasons available to them.'
    ],['skepticism','stoicism','epicureanism','epistemology'],['zeno','chrysippus','epicurus','sextus-empiricus'],[]),
    section('epistemology','Skepticism as a pressure test for knowledge',[
      'Skeptical challenges force theories of knowledge to specify their standards. What distinguishes knowledge from a lucky true belief? How can perception be trusted when conditions alter appearances? Can a criterion of truth justify itself without circularity? Does disagreement among informed people undermine confidence? How far must reasons extend before belief becomes responsible? Responses to these questions generate foundationalism, coherentism, fallibilism, externalism, contextualism, and other approaches, even when those views reject skeptical suspension.',
      'The skeptic’s role is not necessarily to defeat knowledge permanently. A successful answer may clarify that certainty was never required, that practical inquiry can be self-correcting, or that some doubts lack genuine reason. Conversely, a theory that dismisses skepticism too quickly may hide its dependence on unexamined assumptions. Skepticism is strongest when it discriminates among claims and standards rather than using the mere possibility of error to deny everything. It keeps epistemology answerable to the difference between confidence, justification, and possession of truth.'
    ],['skepticism','epistemology','logic'],['sextus-empiricus','descartes','hume'],[]),
    section('early-modern','Montaigne, Descartes, Hume, and modern doubt',[
      'The recovery and circulation of Sextus Empiricus in early modern Europe intensified debates about knowledge, religion, and method. Montaigne used skeptical materials to expose human presumption and examine custom, judgment, and self-knowledge. His skepticism does not simply repeat ancient Pyrrhonism; it belongs to a literary, moral, and religious project shaped by his own period. The availability of ancient arguments nevertheless made it harder for inherited authorities to treat disagreement and uncertainty as minor problems.',
      'Descartes radicalizes doubt methodically in order to discover a foundation immune to it, a goal unlike Pyrrhonian suspension. Hume develops skeptical arguments about causation, induction, self, and reason while emphasizing that nature returns people to ordinary belief and practice. Later philosophy repeatedly reconstructs skepticism as an opponent, method, or limit. These receptions often turn an ancient practice of non-assent into a theoretical problem demanding refutation. Comparing them reveals that “skepticism” can name very different relations among inquiry, certainty, life, and tranquility.'
    ],['skepticism','epistemology','empiricism','rationalism'],['sextus-empiricus','descartes','hume'],['Outlines of Pyrrhonism','Meditations on First Philosophy']),
    section('misunderstandings-reading','Misunderstandings and how to start reading skepticism',[
      'Skeptics do not simply believe nothing, because that statement itself can become a dogmatic belief. Skepticism is not cynicism in the modern sense of assuming bad motives, and it is not relativism claiming every view is equally true. It is also not denialism, which dismisses well-supported conclusions for strategic or ideological reasons. Genuine skeptical inquiry attends closely to evidence and opposing arguments. Suspension is warranted by unresolved reasons, not by convenience or the desire to avoid an unwelcome fact.',
      'Begin with Sextus Empiricus’ Outlines of Pyrrhonism, especially the account of skepticism, the modes, and the response to inactivity. Read slowly enough to notice when Sextus reports an appearance rather than asserts a doctrine. Then study Academic Skepticism through reliable collections of evidence on Arcesilaus and Carneades, comparing their arguments with Stoic epistemology. Add Montaigne, Descartes, and Hume to see ancient materials transformed. The guiding question is not “How can I doubt this?” but “What would justify assent here, and has the inquiry actually supplied it?”',
      'Good skeptical reading also asks when doubt has become selective. A person who demands impossible certainty from an unwelcome conclusion while accepting convenient claims casually is not suspending judgment consistently. Ancient skepticism is intellectually difficult because it turns the demand for reasons back on the skeptic’s own habits, loyalties, and formulas.'
    ],['skepticism','epistemology','stoicism'],['sextus-empiricus','pyrrho','descartes','hume'],['Outlines of Pyrrhonism','Meditations on First Philosophy'])
  ]
};
